import React, { useEffect, useState } from 'react';
import { moviesAPI } from "../utils/api";

function Movies() {
  const [myMovies, setMyMovies] = useState([]);
  const [communityMovies, setCommunityMovies] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchMyMovies = async () => {
    try {
      const response = await moviesAPI.getMovies();
      setMyMovies(response.data);
    } catch (error) {
      console.error('Error fetching my movies:', error);
    }
  };

  const fetchCommunityMovies = async () => {
    try {
      const response = await moviesAPI.getCommunityMovies();
      setCommunityMovies(response.data);
    } catch (error) {
      console.error('Error fetching community movies:', error);
    }
  };

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      await Promise.all([fetchMyMovies(), fetchCommunityMovies()]);
      setLoading(false);
    };

    loadData();
  }, []);

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div style={{ padding: '20px' }}>
      <h1>My Movie Watchlist</h1>

      {myMovies.length === 0 ? (
        <p>You have no movies yet.</p>
      ) : (
        <div style={{ display: 'grid', gap: '16px', marginBottom: '40px' }}>
          {myMovies.map((movie) => (
            <div
              key={movie._id}
              style={{
                border: '1px solid #ccc',
                borderRadius: '12px',
                padding: '16px',
              }}
            >
              <h3>{movie.title}</h3>
              <p>Genre: {movie.genre || '‚Äî'}</p>
              <p>Year: {movie.year || '‚Äî'}</p>
              <p>Status: {movie.status || '‚Äî'}</p>
              <p>Rating: {movie.rating || '‚Äî'}</p>
              <p>Comment: {movie.comment || '‚Äî'}</p>
            </div>
          ))}
        </div>
      )}

      <h1>Community Watchlist</h1>

      {communityMovies.length === 0 ? (
        <p>No movies from other users yet.</p>
      ) : (
        <div style={{ display: 'grid', gap: '16px' }}>
          {communityMovies.map((movie) => (
            <div
              key={movie._id}
              style={{
                border: '1px solid #ccc',
                borderRadius: '12px',
                padding: '16px',
              }}
            >
              <h3>{movie.title}</h3>
              <p>Genre: {movie.genre || '‚Äî'}</p>
              <p>Year: {movie.year || '‚Äî'}</p>
              <p>Status: {movie.status || '‚Äî'}</p>
              <p>Rating: {movie.rating || '‚Äî'}</p>
              <p>Comment: {movie.comment || '‚Äî'}</p>
              <p>
                Added by:{' '}
                {movie.user?.name || movie.user?.email || 'Unknown user'}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Movies;
